const AI_RESPONSES = {
  "track": { text: "I can help you track your shipment! Please provide your tracking number and I'll pull up the latest status right away. 📦", category: "Freight" },
  "refund": { text: "I understand you'd like a refund. Our policy allows refunds within 30 days of purchase. I'll escalate this to our billing team and you'll receive a response within 24 hours. ✅", category: "Support" },
  "delay": { text: "I apologize for the delay in your shipment. I've flagged this as high priority and notified the dispatch team. You'll receive an updated ETA via email within the hour. 🚚", category: "Freight" },
  "invoice": { text: "I can generate and resend your invoice. Please confirm the order number and preferred email address and I'll have that sent over immediately. 📄", category: "Admin" },
  "cancel": { text: "I can process your cancellation request. Before I proceed, may I ask the reason? This helps us improve our service. Your refund (if eligible) will be processed within 3-5 business days. ❌", category: "Support" },
  "schedule": { text: "I'd be happy to help schedule a pickup or delivery. Please share your preferred date/time window and location. Our dispatch team operates Mon–Sat, 6 AM–8 PM. 📅", category: "Freight" },
  "hello": { text: "Hello! I'm RoBot, Romel's AI Customer Support Assistant. I can help with shipment tracking, refunds, scheduling, invoices, and general inquiries. How can I assist you today? 👋", category: "General" },
  "hi": { text: "Hi there! Welcome to AI-powered support. I'm here to help with orders, freight coordination, billing, and more. What do you need help with? 😊", category: "General" },
  "help": { text: "Sure! Here's what I can assist with:\n• 📦 Track shipments\n• 💰 Process refunds\n• 📅 Schedule pickups/deliveries\n• 📄 Resend invoices\n• 🚚 Report delays\n• ❓ General inquiries\n\nJust type your question!", category: "General" },
  "password": { text: "For security reasons, I can't reset passwords directly in chat. I'll send a secure password reset link to your registered email address right now. Check your inbox in 2–3 minutes. 🔒", category: "Support" },
};

function getAIResponse(input) {
  const lower = input.toLowerCase();
  for (const [key, val] of Object.entries(AI_RESPONSES)) {
    if (lower.includes(key)) return val;
  }
  return { text: "Thanks for reaching out! I've logged your inquiry and will connect you with a specialist. For urgent matters, please email romel.musico1023@gmail.com. Your reference number is #" + Math.floor(Math.random()*90000+10000) + ". 🎯", category: "General" };
}

