  const [stats, setStats] = useState({ resolved: 0, avgTime: 0, satisfaction: 100 });
  const bottomRef = useRef(null);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages, typing]);

  const send = () => {
    if (!input.trim()) return;
    const userMsg = input.trim(); setInput("");
    setMessages(m => [...m, { role: "user", text: userMsg, ts: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) }]);
    setTyping(true);
    setTimeout(() => {
      const res = getAIResponse(userMsg);
      setTyping(false);
      setMessages(m => [...m, { role: "bot", text: res.text, ts: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }), cat: res.category }]);
      setStats(s => ({ resolved: s.resolved + 1, avgTime: Math.floor(Math.random() * 3 + 1), satisfaction: Math.min(100, s.satisfaction + 1) }));
    }, 1200 + Math.random() * 600);
  };

  const catColor = { General: t.accent, Freight: "#f59e0b", Support: t.cyan, Admin: t.purple };
